import java.sql.*;   //Import necessary Java Libraries 
public class java_44733_JDBCQueryHandler_A03 {    //Declare the Class Name (Main Method) inside a Main/Class Block for simplicity of syntax
     public static void main(String[] args){     	//Define our Main Function or method to run Program	
           String url = "jdbc:mysql://localhost:3306/mydatabase";  //Connection URL with database and port number (Replace the values as per requirement)  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
           String username = "root" ;           		//Your MySQL Root Username, replace it according to your server configuration 						      //Change this with real user for production use.  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
           String password = "password";             // Your root User Password (replace as per requirement)	                                     	//Again, change it to your actual server credentials in a production environment.  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
           try{                            //Start of Try Block for Exception Handling – In case an exception occurs within this block (like no network connectivity, wrong URL etc.) it will catch and handle the error	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
               Class.forName("com.mysql.jdbc.Driver");  //Loads MySQL Driver into Java Memory (this line is required for every JDBC Connection)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
               System.out.println("Connected to database: " + url); //Prints out a message indicating whether or not the connection was successful – this is optional and depends on your needs	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
               Connection con = DriverManager.getConnection(url, username , password); //Establishes a Java-to - MySQL database connection (this line is required for every JDBC Statement)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
               PreparedStatement pstmt = con.prepareStatement("INSERT INTO EMPLOYEE(ID,NAME,DEPARTMENT,SALARY) VALUES (?, ? ,? ,?)"); //Preparation of JDBC Statement	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
               pstmt.setInt(1, 20);                    	//Setting values in PreparedStatement for the SQL Query (this line is required only if there's a single value to be set)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
               pstmt.setString(2, "John");                //Setting values in PreparedStatement for the SQL Query (this line is required only if there's a single value to be set)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
               pstmt.setString(3, "IT");                   //Setting values in PreparedStatement for the SQL Query (this line is required only if there's a single value to be set)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
               pstmt.setDouble(4, 300);                   //Setting values in PreparedStatement for the SQL Query (this line is required only if there's a single value to be set)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
               pstmt.executeUpdate();                     //Executes Updates and PreparedStatements in the database (this line is required for every JDBC Statement, it's executed after setting values)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
               con.close();                              //Closes Java - MySQL Database Connection(if any open connection exists in the database). (this line is required for every JDBC Statement)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
           }catch(SQLException se){                      //Start of Catch Block to handle SQL Exceptions. It catches the exceptions raised by PreparedStatement and Connection objects in JDBC	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
               System.out.println("Connection Failed! \n" + se);  //Handles Errors while connecting to Database (this line is required for every JDBC Statement)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
           }catch(Exception e){                         	//Start of Catch Block. Handles all the exceptions that are not specific to PreparedStatement, Connection or SQLExceptions (this line is required for every JDBC Statement)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
               System.out.println("Error Occurred! \n" + e);  //Handles Errors (this line is required for every JDBC Statement)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
           }                                    	//End of Main Function or method to run Program. This ends the program execution and all resources are released (this line is required for every JDBC Statement)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
      }                                    	//End of Main Function or method to run Program. This ends the program execution and all resources are released (this line is required for every JDBC Statement)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .                 
}  //End of Java Class Definition with Main Method, this closes the entire file. This example follows a simple and specific way to handle database operations in JDBC (this line is required for every piece code)	  		   									    			                                                   								                                                                             	   							      	       	 	     ​        ...          .......         .